import React from "react";

const ProgressBar = ({ progress = 0, showLabel = true }) => {
  const p = Math.min(100, Math.max(0, progress));
  const color = p >= 80 ? "#43d9ad" : p >= 40 ? "#ffbb57" : "#6c63ff";

  return (
    <div className="w-100">
      {showLabel && (
        <div className="d-flex justify-content-between align-items-center mb-1">
          <small style={{ color: "#666688" }}>Progress</small>
          <small className="fw-bold" style={{ color: "#e8e8f0" }}>{p}%</small>
        </div>
      )}
      <div className="progress" style={{ height: 8, background: "#2a2a4a", borderRadius: 50 }}>
        <div
          className="progress-bar"
          role="progressbar"
          style={{
            width: `${p}%`,
            background: `linear-gradient(90deg, ${color}, ${color}cc)`,
            borderRadius: 50,
            transition: "width 0.6s cubic-bezier(0.4,0,0.2,1)"
          }}
          aria-valuenow={p}
          aria-valuemin={0}
          aria-valuemax={100}
        />
      </div>
      {p === 100 && (
        <small className="mt-1 d-block" style={{ color: "#43d9ad" }}>✅ Completed!</small>
      )}
    </div>
  );
};

export default ProgressBar;
